public double solve(final UnivariateRealFunction f,
                    final double min, final double max, final double initial)
    throws MaxIterationsExceededException, FunctionEvaluationException {

    clearResult();
    verifySequence(min, initial, max);

    // return the initial guess if it is good enough
    double yInitial = f.value(initial);
    if (Math.abs(yInitial) <= functionValueAccuracy) {
        setResult(initial, 0);
        return result;
    }

    // return the first endpoint if it is good enough
    double yMin = f.value(min);
    if (Math.abs(yMin) <= functionValueAccuracy) {
        setResult(min, 0);
        return result;
    }

    // reduce interval if min and initial bracket the root
    if (yInitial * yMin < 0) {
      return findRoot(f, min, initial);
    }

    // return the second endpoint if it is good enough
    double yMax = f.value(max);
    if (Math.abs(yMax) <= functionValueAccuracy) {
        setResult(max, 0);
        return result;
    }

    // reduce interval if initial and max bracket the root
    if (yInitial * yMax < 0) {
       return findRoot(f, initial, max);
    }

    if (yMin * yMax > 0) {
        throw MathRuntimeException.createIllegalArgumentException(
              NON_BRACKETING_MESSAGE, min, max, yMin, yMax);
    }

    // full Brent algorithm starting with provided initial guess
    return findRoot(f, min, max);

}
private double findRoot(UnivariateRealFunction f, double x1, double x2){
    int iteration = 0;
    double error,tmp=0;
    do{
        ++iteration;
        tmp = bisectionMethodStep(f,x1,x2);
        error = Math.abs(tmp - x1);
        if (error<rootFindingPrecision){
            break;
        }else{
          double yTmp = f.value(tmp);
           if (yTmp*f.value(x1)>0){
               x1 = tmp;
           }else{
                x2 = tmp;
           }
        }  
    }while(true);
    return tmp;
}

protected double bisectionMethodStep(UnivariateRealFunction f,double left,double right){
    return left + (right - left)/2;
}

void setResult(double solution, long numIters) {
    this.result = solution;
    this.numIterations = numIters;
}

void clearResult() {
    result = Double.NaN;
    numIterations = -1;
}

boolean verifySequence(double sequencePoint1, double sequencePoint2, double sequencePoint3) {
    if (!Double.isFinite(sequencePoint1)) {
        throw new IllegalStateException("sequence point 1 not finite");
    }

    if (!Double.isFinite(sequencePoint2)) {
        throw new IllegalStateException("sequence point 2 not finite");
    }

    if (!Double.isFinite(sequencePoint3)) {
        throw new IllegalStateException("sequence point 3 not finite");
    }

    boolean conditionOne = !((sequencePoint2 < sequencePoint1 && sequencePoint2 > sequencePoint3) || (sequencePoint2 > sequencePoint1 && sequencePoint2 < sequencePoint3));

    boolean conditionTwo = !(sequencePoint1 == sequencePoint3);

    if (!conditionOne ||!conditionTwo) {
        throw new IllegalStateException("invalid search sequence encountered");
    }

    return true;
}

